  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { normalizeRectBounds } from '@/clipboard/planClipboard';
  6→import { getFloorElevation } from '@/domain/floorModels';
  7→import { useEditorTool } from '@/editor/useEditorTool';
  8→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  9→import { TOOLS } from '@/editor/tools';
 10→import ClipboardPreviewLayer from './ClipboardPreviewLayer';
 11→import GridRenderer from './GridRenderer';
 12→import SlabRenderer from './SlabRenderer';
 13→import WallRenderer from './WallRenderer';
 14→import BeamRenderer from './BeamRenderer';
 15→import StairRenderer from './StairRenderer';
 16→import DoorRenderer from './DoorRenderer';
 17→import WindowRenderer from './WindowRenderer';
 18→import RoomRenderer from './RoomRenderer';
 19→import AnnotationRenderer from './AnnotationRenderer';
 20→import ElevationRenderer from './ElevationRenderer';
 21→import SectionRenderer from './SectionRenderer';
 22→import SelectionOverlay from './SelectionOverlay';
 23→import DimensionPreview from './DimensionPreview';
 24→import WallPreview from './WallPreview';
 25→import LandingRenderer from './LandingRenderer';
 26→import LandingPreview from './LandingPreview';
 27→import ColumnRenderer from './ColumnRenderer';
 28→import ColumnPreview from './ColumnPreview';
 29→import BeamPreview from './BeamPreview';
 30→import StairPreview from './StairPreview';
 31→import SlabPreview from './SlabPreview';
 32→import DoorWindowPreview from './DoorWindowPreview';
 33→import RoomPreview from './RoomPreview';
 34→import SectionCutRenderer from './SectionCutRenderer';
 35→import SectionCutPreview from './SectionCutPreview';
 36→import RegionSelectionOverlay from './RegionSelectionOverlay';
 37→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 38→import { isTypingTarget } from '@/utils/keyboard';
 39→import styles from './SvgCanvas.module.css';
 40→
 41→function screenToModel(screenX, screenY, viewport, svgRect) {
 42→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 43→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 44→  return { x, y };
 45→}
 46→
 47→export default function SvgCanvas() {
 48→  const svgRef = useRef(null);
 49→  const isPanning = useRef(false);
 50→  const lastPanPos = useRef({ x: 0, y: 0 });
 51→  const spaceHeld = useRef(false);
 52→  const cursorPosRef = useRef({ x: 0, y: 0 });
 53→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 54→
 55→  const { project, dispatch, getFloor } = useProject();
 56→  const editor = useEditor();
 57→  const {
 58→    activeTool, selectedId, selectedType, toolState,
 59→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 60→    regionSelection, pastePreview, maximizedPanel,
 61→    dispatch: editorDispatch,
 62→  } = editor;
 63→
 64→  const floor = getFloor(activeFloorId);
 65→  const {
 66→    copySelection,
 67→    cutSelection,
 68→    beginPaste,
 69→    updatePastePreview,
 70→    cancelPaste,
 71→    placePaste,
 72→    previewContent,
 73→  } = usePlanClipboardController();
 74→
 75→  const tool = useEditorTool({
 76→    activeTool,
 77→    dispatch,
 78→    editorDispatch,
 79→    project,
 80→    getFloor,
 81→    activeFloorId,
 82→    viewport,
 83→    snapEnabled,
 84→    selectedId,
 85→    selectedType,
 86→    toolState,
 87→    viewMode,
 88→  });
 89→
 90→  const getModelPos = useCallback((e) => {
 91→    const rect = svgRef.current.getBoundingClientRect();
 92→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 93→  }, [viewport]);
 94→
 95→  const handleMouseDown = useCallback((e) => {
 96→    // Middle mouse or space+left for pan
 97→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 98→      isPanning.current = true;
 99→      lastPanPos.current = { x: e.clientX, y: e.clientY };
100→      e.preventDefault();
101→      return;
102→    }
103→
104→    const modelPos = getModelPos(e);
105→    if (pastePreview?.active && e.button === 0) {
106→      placePaste(modelPos);
107→      return;
108→    }
109→    tool.onMouseDown(modelPos, e);
110→  }, [getModelPos, pastePreview, placePaste, tool]);
111→
112→  const handleMouseMove = useCallback((e) => {
113→    if (isPanning.current) {
114→      const dx = e.clientX - lastPanPos.current.x;
115→      const dy = e.clientY - lastPanPos.current.y;
116→      editorDispatch({ type: 'PAN', dx, dy });
117→      lastPanPos.current = { x: e.clientX, y: e.clientY };
118→      return;
119→    }
120→
121→    const modelPos = getModelPos(e);
122→    cursorPosRef.current = modelPos;
123→    setCursorPos(modelPos);
124→    if (pastePreview?.active) {
125→      updatePastePreview(modelPos);
126→      return;
127→    }
128→    tool.onMouseMove(modelPos, e);
129→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
130→
131→  const handleMouseUp = useCallback((e) => {
132→    if (isPanning.current) {
133→      isPanning.current = false;
134→      return;
135→    }
136→    if (pastePreview?.active) return;
137→    const modelPos = getModelPos(e);
138→    tool.onMouseUp(modelPos, e);
139→  }, [getModelPos, pastePreview, tool]);
140→
141→  const handleDoubleClick = useCallback((e) => {
142→    if (pastePreview?.active) return;
143→    const modelPos = getModelPos(e);
144→    tool.onDoubleClick(modelPos, e);
145→  }, [getModelPos, pastePreview, tool]);
146→
147→  const handleWheel = useCallback((e) => {
148→    e.preventDefault();
149→    const rect = svgRef.current.getBoundingClientRect();
150→    const mouseX = e.clientX - rect.left;
151→    const mouseY = e.clientY - rect.top;
152→
153→    const direction = e.deltaY < 0 ? 1 : -1;
154→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
155→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
156→
157→    // Zoom centered on cursor
158→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
159→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
160→
161→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
162→  }, [viewport, editorDispatch]);
163→
164→  useEffect(() => {
165→    if (!statusMessage) return undefined;
166→
167→    const timer = window.setTimeout(() => {
168→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
169→    }, 2500);
170→
171→    return () => window.clearTimeout(timer);
172→  }, [statusMessage, editorDispatch]);
173→
174→  useEffect(() => {
175→    const handleKeyDown = (e) => {
176→      if (isTypingTarget(e.target)) return;
177→
178→      if (e.key === ' ') {
179→        spaceHeld.current = true;
180→        e.preventDefault();
181→      }
182→
183→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
184→        const key = e.key.toLowerCase();
185→        if (key === 'c') {
186→          e.preventDefault();
187→          copySelection();
188→          return;
189→        }
190→        if (key === 'x') {
191→          e.preventDefault();
192→          cutSelection();
193→          return;
194→        }
195→        if (key === 'v') {
196→          e.preventDefault();
197→          beginPaste(cursorPosRef.current);
198→          return;
199→        }
200→      }
201→
202→      if (e.key === 'Escape' && pastePreview?.active) {
203→        e.preventDefault();
204→        cancelPaste();
205→        return;
206→      }
207→
208→      // Tool shortcuts
209→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
210→        switch (e.key.toLowerCase()) {
211→          case 'v':
212→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
213→            return;
214→          case 'm':
215→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
216→            return;
217→          case 'w':
218→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
219→            return;
220→          case 'b':
221→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
222→            return;
223→          case 't':
224→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
225→            return;
226→          case 'q':
227→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
228→            return;
229→          case 's':
230→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
231→            return;
232→          case 'r':
233→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
234→            return;
235→          case 'd':
236→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
237→            return;
238→          case 'n':
239→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
240→            return;
241→          case 'c':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
243→            return;
244→          case 'l':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
246→            return;
247→        }
248→      }
249→
250→      tool.onKeyDown(e);
251→    };
252→
253→    const handleKeyUp = (e) => {
254→      if (isTypingTarget(e.target)) return;
255→
256→      if (e.key === ' ') {
257→        spaceHeld.current = false;
258→      }
259→    };
260→
261→    window.addEventListener('keydown', handleKeyDown);
262→    window.addEventListener('keyup', handleKeyUp);
263→    return () => {
264→      window.removeEventListener('keydown', handleKeyDown);
265→      window.removeEventListener('keyup', handleKeyUp);
266→    };
267→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
268→
269→  // Prevent default context menu on SVG
270→  useEffect(() => {
271→    const svg = svgRef.current;
272→    if (!svg) return;
273→    const prevent = (e) => e.preventDefault();
274→    svg.addEventListener('contextmenu', prevent);
275→    svg.addEventListener('wheel', handleWheel, { passive: false });
276→    return () => {
277→      svg.removeEventListener('contextmenu', prevent);
278→      svg.removeEventListener('wheel', handleWheel);
279→    };
280→  }, [handleWheel]);
281→
282→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
283→  const zoomPercent = Math.round(viewport.zoom * 1000);
284→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
285→  const isCanvasMaximized = maximizedPanel === 'canvas';
286→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
287→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
288→    : null;
289→  const selectionCount = regionSelection?.objectCount || 0;
290→
291→  return (
292→    <div className={styles.canvasContainer}>
293→      <svg
294→        ref={svgRef}
295→        className={styles.svg}
296→        style={{ cursor }}
297→        onMouseDown={handleMouseDown}
298→        onMouseMove={handleMouseMove}
299→        onMouseUp={handleMouseUp}
300→        onDoubleClick={handleDoubleClick}
301→      >
302→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
303→          {viewMode === 'plan' && showGrid && <GridRenderer />}
304→          {viewMode === 'plan' && showGrid && (
305→            <rect
306→              x={-100000} y={-100000}
307→              width={200000} height={200000}
308→              fill="url(#grid-major)"
309→              style={{ pointerEvents: 'none' }}
310→            />
311→          )}
312→          {floor && (
313→            viewMode === 'plan' ? (
314→              <>
315→                {(floor.slabs || []).map(slab => (
316→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
317→                ))}
318→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
319→                <RoomPreview toolState={toolState} activeTool={activeTool} />
320→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
321→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
322→                <StairRenderer stairs={floor.stairs || []} />
323→                <LandingRenderer landings={floor.landings || []} />
324→                <ColumnRenderer columns={floor.columns || []} />
325→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
326→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
327→                {(floor.sectionCuts || []).map(sc => (
328→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
329→                ))}
330→                <AnnotationRenderer floor={floor} />
331→                <ClipboardPreviewLayer content={previewContent} />
332→                <RegionSelectionOverlay
333→                  marqueeBounds={marqueeBounds}
334→                  selectionBounds={regionSelection?.bounds || null}
335→                />
336→                <SelectionOverlay
337→                  selectedId={selectedId}
338→                  selectedType={selectedType}
339→                  floor={floor}
340→                  zoom={viewport.zoom}
341→                />
342→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
343→                <WallPreview toolState={toolState} activeTool={activeTool} />
344→                <SlabPreview toolState={toolState} activeTool={activeTool} />
345→                <BeamPreview
346→                  toolState={toolState}
347→                  activeTool={activeTool}
348→                  columns={floor.columns || []}
349→                  floorLevel={getFloorElevation(floor)}
350→                />
351→                <StairPreview
352→                  toolState={toolState}
353→                  activeTool={activeTool}
354→                  floorId={floor.id}
355→                />
356→                <DoorWindowPreview
357→                  toolState={toolState}
358→                  activeTool={activeTool}
359→                  walls={floor.walls}
360→                />
361→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
362→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
363→                <LandingPreview toolState={toolState} activeTool={activeTool} />
364→              </>
365→            ) : viewMode === 'section_view' ? (
366→              <SectionRenderer
367→                project={project}
368→                floor={floor}
369→                activeSectionCutId={activeSectionCutId}
370→              />
371→            ) : (
372→              <ElevationRenderer
373→                project={project}
374→                floor={floor}
375→                viewMode={viewMode}
376→                selectedId={selectedId}
377→                selectedType={selectedType}
378→              />
379→            )
380→          )}
381→        </g>
382→      </svg>
383→      <button
384→        className={styles.expandBtn}
385→        onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
386→        title={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
387→        aria-label={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
388→      >
389→        {isCanvasMaximized ? <CollapseIcon /> : <ExpandIcon />}
390→      </button>
391→      <div className={styles.statusBar}>
392→        <span>X: {Math.round(cursorPos.x)} mm</span>
393→        <span>Y: {Math.round(cursorPos.y)} mm</span>
394→        <span>Zoom: {zoomPercent}%</span>
395→        <span>View: {viewMode}</span>
396→        <span>Tool: {displayedTool}</span>
397→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
398→        {pastePreview?.active && <span>Paste: click to place</span>}
399→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
400→      </div>
401→    </div>
402→  );
403→}
