143→function JalousieWindow({ win, info, wall }) {
144→  const dir = wallDirection(wall);
145→  const perp = perpendicular(dir);
146→  const halfThick = wall.thickness / 2;
147→  const slats = 5;
148→
149→  // Evenly space slats along the window width
150→  const lines = [];
151→  for (let i = 1; i <= slats; i++) {
152→    const t = i / (slats + 1);
153→    const along = add(info.start, scale(dir, win.width * t));
154→    lines.push({
155→      x1: add(along, scale(perp, -halfThick * 0.7)).x,
156→      y1: add(along, scale(perp, -halfThick * 0.7)).y,
157→      x2: add(along, scale(perp, halfThick * 0.7)).x,
158→      y2: add(along, scale(perp, halfThick * 0.7)).y,
159→    });
160→  }
161→
162→  return (
163→    <>
164→      {/* Center line */}
165→      <line
166→        x1={info.start.x} y1={info.start.y}
167→        x2={info.end.x} y2={info.end.y}
168→        stroke="var(--color-wall-fill)"
169→        strokeWidth={2}
170→        vectorEffect="non-scaling-stroke"
171→      />
172→      {/* Perpendicular slat lines */}
173→      {lines.map((l, i) => (
174→        <line
175→          key={i}
176→          x1={l.x1} y1={l.y1}
177→          x2={l.x2} y2={l.y2}
178→          stroke="var(--color-wall-fill)"
179→          strokeWidth={1}
180→          vectorEffect="non-scaling-stroke"
181→        />
182→      ))}
183→    </>
184→  );
185→}
